// src/components/Login.js
import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import './Auth.css'; // Import shared CSS for Login/Signup

const Login = () => {
    const [formData, setFormData] = useState({ email: '', password: '' });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate(); // Initialize useNavigate

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            const response = await axios.post('http://localhost:5000/api/auth/login', formData);
            localStorage.setItem('token', response.data.token); // Store the JWT token
            localStorage.setItem('userType', response.data.role); // Store user type

            // Redirect based on user role
            navigate(response.data.role === 'farmer' ? '/farmer-home' : '/');
        } catch (err) {
            setError(err.response?.data?.message || 'Login failed. Please check your credentials.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-page-container">
            <div className="auth-background">
                <div className="wheat-pattern"></div>
                <div className="auth-overlay"></div>
            </div>

            <motion.div 
                className="auth-container"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
            >
                <motion.div 
                    className="auth-box"
                    initial={{ scale: 0.9, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    transition={{ duration: 0.5, delay: 0.2 }}
                >
                    <div className="auth-logo">
                        <img src="/logo192.png" alt="Agro Seva" width="60" />
                    </div>

                    <motion.h2 
                        className="auth-title"
                        initial={{ y: -20, opacity: 0 }}
                        animate={{ y: 0, opacity: 1 }}
                        transition={{ duration: 0.5, delay: 0.3 }}
                    >
                        Welcome Back
                    </motion.h2>

                    <motion.p 
                        className="auth-subtitle"
                        initial={{ y: -20, opacity: 0 }}
                        animate={{ y: 0, opacity: 1 }}
                        transition={{ duration: 0.5, delay: 0.4 }}
                    >
                        Login to access your account
                    </motion.p>

                    <motion.form 
                        onSubmit={handleSubmit}
                        initial={{ y: 20, opacity: 0 }}
                        animate={{ y: 0, opacity: 1 }}
                        transition={{ duration: 0.5, delay: 0.5 }}
                    >
                        <div className="input-group">
                            <label htmlFor="email">Email</label>
                            <motion.input 
                                whileFocus={{ scale: 1.02 }}
                                transition={{ duration: 0.2 }}
                                id="email"
                                name="email" 
                                type="email" 
                                value={formData.email} 
                                onChange={handleChange} 
                                placeholder="Enter your email" 
                                required 
                            />
                        </div>

                        <div className="input-group">
                            <label htmlFor="password">Password</label>
                            <motion.input 
                                whileFocus={{ scale: 1.02 }}
                                transition={{ duration: 0.2 }}
                                id="password"
                                name="password" 
                                type="password" 
                                value={formData.password} 
                                onChange={handleChange} 
                                placeholder="Enter your password" 
                                required 
                            />
                        </div>

                        <div className="forgot-password">
                            <a href="/forgot-password">Forgot password?</a>
                        </div>

                        <motion.button 
                            type="submit" 
                            disabled={loading}
                            whileHover={{ scale: 1.05 }}
                            whileTap={{ scale: 0.95 }}
                        >
                            {loading ? (
                                <div className="spinner"></div>
                            ) : (
                                'Login'
                            )}
                        </motion.button>

                        {error && (
                            <motion.div 
                                className="auth-error"
                                initial={{ opacity: 0, y: -10 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ duration: 0.3 }}
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <circle cx="12" cy="12" r="10"></circle>
                                    <line x1="12" y1="8" x2="12" y2="12"></line>
                                    <line x1="12" y1="16" x2="12.01" y2="16"></line>
                                </svg>
                                {error}
                            </motion.div>
                        )}
                    </motion.form>

                    <div className="auth-footer">
                        <p>Don't have an account? <a href="/Signup">Sign Up</a></p>
                    </div>
                </motion.div>
            </motion.div>
        </div>
    );
};

export default Login;
